import type { CheckpointMeta } from '../lib/utils/ai-metrics-utils';

interface Props {
  checkpoints: CheckpointMeta[];
}
const { checkpoints } = Astro.props;

const sorted = [...checkpoints].sort(
  (a, b) => new Date(a.commit_date).getTime() - new Date(b.commit_date).getTime(),
);
const labels = sorted.map((c) => c.checkpoint_id.slice(0, 8));

// Metric 1: agent_percentage time-series (lightweight-charts)
const m1Series = sorted.map((c) => ({
  time: Math.floor(new Date(c.commit_date).getTime() / 1000),
  value: c.agent_percentage,
}));

// Metric 2: pure-AI commit rate stat card
const pureAiCount = checkpoints.filter((c) => c.agent_percentage === 100).length;
const pureAiRate =
  checkpoints.length > 0 ? Math.round((pureAiCount / checkpoints.length) * 100) : 0;

// Metric 3: human modification rate bar chart
const m3Values = sorted.map(
  (c) => c.agent_lines === 0 ? 0 : Math.round((c.human_modified / c.agent_lines) * 100 * 10) / 10,
);

// Metric 4: stacked bar — agent/human lines per checkpoint
const m4Datasets = JSON.stringify([
  { label: 'Agent Lines', data: sorted.map((c) => c.agent_lines), backgroundColor: '#8b5cf6' },
  { label: 'Human Added', data: sorted.map((c) => c.human_added), backgroundColor: '#22c55e' },
  {
    label: 'Human Modified',
    data: sorted.map((c) => c.human_modified),
    backgroundColor: '#f59e0b',
  },
  {
    label: 'Human Removed',
    data: sorted.map((c) => c.human_removed),
    backgroundColor: '#ef4444',
  },
]);

// Metric 5: cumulative zero-human-touch lines stat card
const m5Value = checkpoints
  .filter((c) => c.human_added === 0 && c.human_modified === 0 && c.human_removed === 0)
  .reduce((sum, c) => sum + c.agent_lines, 0);
