    label: 'Cache Creation',
    data: sorted.map((c) => c.tokens.cache_creation),
    backgroundColor: '#00f5ff',
  },
  {
    label: 'Cache Read',
    data: sorted.map((c) => c.tokens.cache_read),
    backgroundColor: '#22c55e',
  },
  { label: 'Output', data: sorted.map((c) => c.tokens.output), backgroundColor: '#f59e0b' },
]);

// Metric 7: cache leverage score time-series (lightweight-charts)
const m7Series = sorted.map((c) => {
  const total = c.tokens.input + c.tokens.cache_creation + c.tokens.cache_read + c.tokens.output;
  return {
    time: Math.floor(new Date(c.commit_date).getTime() / 1000),
    value: total > 0 ? Math.round((c.tokens.cache_read / total) * 1000) / 10 : 0,
  };
});

// Metric 8: API call count (turns.length per checkpoint)
const m8Values = sorted.map((c) => c.turns.length);

// Metric 9: model distribution doughnut
const modelMap = new Map<string, number>();
for (const cp of checkpoints) {
  for (const turn of cp.turns) {
    modelMap.set(turn.model, (modelMap.get(turn.model) ?? 0) + 1);
  }
}
const m9Labels = [...modelMap.keys()];
const m9Values = [...modelMap.values()];
