---
import type { CheckpointMeta } from '../lib/utils/ai-metrics-utils';

interface Props {
  checkpoints: CheckpointMeta[];
}
const { checkpoints } = Astro.props;

const sorted = [...checkpoints].sort(
  (a, b) => new Date(a.commit_date).getTime() - new Date(b.commit_date).getTime(),
);
const labels = sorted.map((c) => c.checkpoint_id.slice(0, 8));

// Metric 10: friction count per checkpoint
const m10Values = sorted.map((c) => c.summary.friction.length);

// Metric 11: open_items count time-series (lightweight-charts)
const m11Series = sorted.map((c) => ({
  time: Math.floor(new Date(c.commit_date).getTime() / 1000),
  value: c.summary.open_items.length,
}));

// Metric 12: learnings sum per checkpoint
const m12Values = sorted.map((c) => c.learnings.repo + c.learnings.code + c.learnings.workflow);

// Metric 13: scatter — x = turns.length, y = agent_percentage
const m13Points = checkpoints.map((c) => ({ x: c.turns.length, y: c.agent_percentage }));
