  import { createChart, LineSeries } from 'lightweight-charts';
  import { Chart, registerables } from 'chart.js';
  import { CHART_COLORS } from '../lib/theme-constants';
  import { DARK_CHART_OPTIONS } from '../lib/utils/ai-metrics-utils';

  Chart.register(...registerables);

  // Metric 10 — bar chart (friction count)
  const m10Canvas = document.getElementById('metric-10') as HTMLCanvasElement | null;
  if (m10Canvas) {
    const labels: string[] = JSON.parse(m10Canvas.dataset.labels ?? '[]');
    const values: number[] = JSON.parse(m10Canvas.dataset.values ?? '[]');
    if (!values.length) {
      const p10 = m10Canvas.parentElement;
      if (p10) p10.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:#606070;font-family:Inter,sans-serif;font-size:14px">No data available</div>';
    } else {
      new Chart(m10Canvas, {
        type: 'bar',
        data: {
          labels,
          datasets: [{ data: values, backgroundColor: '#ef4444', borderRadius: 3 }],
        },
        options: DARK_CHART_OPTIONS,
      });
    }
  }

  // Metric 11 — lightweight-charts line (open items)
  const m11Container = document.getElementById('metric-11') as HTMLDivElement | null;
  if (m11Container) {
    const rawSeries: Array<{ time: number; value: number }> = JSON.parse(
      m11Container.dataset.series ?? '[]',
    );
    if (!rawSeries.length) {
      m11Container.innerHTML =
        '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:#606070;font-family:Inter,sans-serif;font-size:14px">No data available</div>';
    } else {
      const chart = createChart(m11Container, {
        layout: { background: { color: 'transparent' }, textColor: CHART_COLORS.textColor },
        grid: {
          vertLines: { color: CHART_COLORS.gridLinesColor },
          horzLines: { color: CHART_COLORS.gridLinesColor },
        },
        rightPriceScale: { borderVisible: false },
        timeScale: { borderVisible: false, timeVisible: false },
        handleScroll: false,
        handleScale: false,
        autoSize: true,
      });
      const series = chart.addSeries(LineSeries, {
        color: '#f59e0b',
        lineWidth: 2,
        pointMarkersVisible: true,
      });
      const deduped11 = rawSeries.filter((p, i) => i === 0 || p.time !== rawSeries[i - 1].time);
      series.setData(deduped11);
      chart.timeScale().fitContent();
    }
  }

  // Metric 12 — bar chart (learnings sum)
  const m12Canvas = document.getElementById('metric-12') as HTMLCanvasElement | null;
  if (m12Canvas) {
    const labels: string[] = JSON.parse(m12Canvas.dataset.labels ?? '[]');
    const values: number[] = JSON.parse(m12Canvas.dataset.values ?? '[]');
    if (!values.length) {
      const p12 = m12Canvas.parentElement;
      if (p12) p12.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:#606070;font-family:Inter,sans-serif;font-size:14px">No data available</div>';
    } else {
      new Chart(m12Canvas, {
        type: 'bar',
        data: {
          labels,
          datasets: [{ data: values, backgroundColor: '#22c55e', borderRadius: 3 }],
        },
        options: DARK_CHART_OPTIONS,
      });
    }
  }

  // Metric 13 — scatter chart
  const m13Canvas = document.getElementById('metric-13') as HTMLCanvasElement | null;
  if (m13Canvas) {
    const points: Array<{ x: number; y: number }> = JSON.parse(m13Canvas.dataset.points ?? '[]');
    if (!points.length) {
      m13Canvas.parentElement!.innerHTML =
        '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:#606070;font-family:Inter,sans-serif;font-size:14px">No data available</div>';
    } else {
      new Chart(m13Canvas, {
        type: 'scatter',
        data: {
          datasets: [
            {
              data: points,
              backgroundColor: '#00f5ff',
              pointRadius: 5,
              pointHoverRadius: 7,
            },
          ],
        },
        options: {
          ...DARK_CHART_OPTIONS,
          plugins: {
            ...DARK_CHART_OPTIONS.plugins,
            tooltip: {
              ...DARK_CHART_OPTIONS.plugins.tooltip,
              callbacks: {
                label: (ctx) => ` turns: ${ctx.parsed.x}, agent: ${ctx.parsed.y}%`,
              },
            },
          },
          scales: {
            ...DARK_CHART_OPTIONS.scales,
            x: { ...DARK_CHART_OPTIONS.scales.x, title: { display: true, text: 'API Calls (turns)', color: '#606070', font: { family: 'Inter', size: 10 } } },
            y: { ...DARK_CHART_OPTIONS.scales.y, title: { display: true, text: 'Agent %', color: '#606070', font: { family: 'Inter', size: 10 } } },
          },
        },
      });
    }
  }
</script>

